    46→// Create handles POST /subscriptions — creates a new subscription.
    47→func (h *SubscriptionsHandler) Create(w http.ResponseWriter, r *http.Request) {
    48→	var sub models.Subscription
    49→	if err := DecodeJSON(r, &sub); err != nil {
    50→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    51→		return
    52→	}
    53→	sub.Type = strings.TrimSpace(sub.Type)
    54→	sub.ChannelID = strings.TrimSpace(sub.ChannelID)
    55→	// Validate type is source_release or semantic_release.
    56→	if sub.Type != "source_release" && sub.Type != "semantic_release" {
    57→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type must be 'source_release' or 'semantic_release'")
    58→		return
    59→	}
    60→	if sub.ChannelID == "" {
    61→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_id is required")
    62→		return
    63→	}
    64→	// Validate that the corresponding ID is set for the type.
    65→	if sub.Type == "source_release" && (sub.SourceID == nil || *sub.SourceID == "") {
    66→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "source_id is required when type is 'source_release'")
    67→		return
    68→	}
    69→	if sub.Type == "semantic_release" && (sub.ProjectID == nil || *sub.ProjectID == "") {
    70→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "project_id is required when type is 'semantic_release'")
    71→		return
    72→	}
    73→	if err := h.store.CreateSubscription(r.Context(), &sub); err != nil {
    74→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create subscription")
    75→		return
    76→	}
    77→	RespondJSON(w, r, http.StatusCreated, sub)
    78→}
